from dataclasses import dataclass
from typing import Any, Callable, Protocol
from langchain_anthropic import ChatAnthropic

@dataclass
class SubAgentResult:
    success: bool
    output: str
    error: str | None = None

class SubAgentFactory(Protocol):
    def __call__(self, task: str, context: dict[str, Any]) -> SubAgentResult: ...

haiku = ChatAnthropic(model="claude-haiku-4-5-20251001")

def code_sub_agent(task: str, context: dict[str, Any]) -> SubAgentResult:
    """Handles code generation and explanation tasks."""
    try:
        resp = haiku.invoke([
            {"role": "system", "content": (
                "You are a code specialist. Write or explain code as requested. "
                "Return only the code or explanation, no commentary."
            )},
            {"role": "user", "content": task},
        ])
        return SubAgentResult(success=True, output=resp.content)
    except Exception as exc:
        return SubAgentResult(success=False, output="", error=str(exc))

def search_sub_agent(task: str, context: dict[str, Any]) -> SubAgentResult:
    """Handles web search and retrieval tasks."""
    try:
        resp = haiku.invoke([
            {"role": "system", "content": "You are a search specialist. Find and summarise relevant information."},
            {"role": "user", "content": task},
        ])
        return SubAgentResult(success=True, output=resp.content)
    except Exception as exc:
        return SubAgentResult(success=False, output="", error=str(exc))

# Registry maps capability → factory
SUB_AGENT_REGISTRY: dict[str, SubAgentFactory] = {
    "code":   code_sub_agent,
    "search": search_sub_agent,
}

def invoke_sub_agent(
    capability: str,
    task: str,
    context: dict[str, Any] | None = None,
) -> SubAgentResult:
    factory = SUB_AGENT_REGISTRY.get(capability)
    if factory is None:
        return SubAgentResult(success=False, output="",
                              error=f"unknown_capability:{capability}")
    return factory(task, context or {})

from langgraph.graph import StateGraph, END
from typing import TypedDict, Annotated
import operator

sonnet = ChatAnthropic(model="claude-sonnet-5")

class ParentState(TypedDict):
    task: str
    sub_agent_results: Annotated[list[dict], operator.add]
    final_answer: str
    errors: Annotated[list[str], operator.add]

CAPABILITY_KEYWORDS = {
    "code":   ["code", "function", "script", "implement", "debug"],
    "search": ["find", "search", "look up", "retrieve", "what is"],
}

def detect_capability(task: str) -> str | None:
    task_lower = task.lower()
    for capability, keywords in CAPABILITY_KEYWORDS.items():
        if any(kw in task_lower for kw in keywords):
            return capability
    return None

def parent_node(state: ParentState) -> dict:
    """Detects what capability is needed and spawns the right sub-agent."""
    capability = detect_capability(state["task"])

    if capability:
        result = invoke_sub_agent(capability, state["task"])
        if result.success:
            return {"sub_agent_results": [{"capability": capability, "output": result.output}]}
        else:
            return {"errors": [f"sub_agent:{capability}:{result.error}"]}

    # No specialist needed — parent handles directly
    resp = sonnet.invoke([
        {"role": "system", "content": "Answer the question directly."},
        {"role": "user",   "content": state["task"]},
    ])
    return {"sub_agent_results": [{"capability": "parent", "output": resp.content}]}

def synthesize_node(state: ParentState) -> dict:
    parts = [r["output"] for r in state["sub_agent_results"] if r.get("output")]
    if len(parts) == 1:
        return {"final_answer": parts[0]}
    resp = sonnet.invoke([
        {"role": "user", "content": "Combine these results into a coherent answer:\n\n" + "\n\n".join(parts)},
    ])
    return {"final_answer": resp.content}

def build_parent_graph():
    builder = StateGraph(ParentState)
    builder.add_node("parent",    parent_node)
    builder.add_node("synthesize", synthesize_node)
    builder.set_entry_point("parent")
    builder.add_edge("parent", "synthesize")
    builder.add_edge("synthesize", END)
    return builder.compile()

from langchain_core.tools import tool
from pydantic import BaseModel

class SpawnRequest(BaseModel):
    capability: str
    task: str

@tool
def spawn_sub_agent(capability: str, task: str) -> str:
    """Invoke a specialist sub-agent. Available capabilities: code, search, file."""
    result = invoke_sub_agent(capability, task)
    if not result.success:
        return f"ERROR: {result.error}"
    return result.output

routing_llm = sonnet.bind_tools([spawn_sub_agent])

def llm_routing_node(state: ParentState) -> dict:
    resp = routing_llm.invoke([
        {"role": "system", "content": (
            "You are a router. Use spawn_sub_agent to delegate to a specialist "
            "if the task needs one, or answer directly if you can handle it."
        )},
        {"role": "user", "content": state["task"]},
    ])
    # If the LLM called spawn_sub_agent, execute the tool call
    if resp.tool_calls:
        call = resp.tool_calls[0]
        output = spawn_sub_agent.invoke(call["args"])
        return {"sub_agent_results": [{"capability": call["args"]["capability"], "output": output}]}
    # Otherwise the LLM answered directly
    return {"sub_agent_results": [{"capability": "parent", "output": resp.content}]}

import os
import subprocess
import tempfile
from pathlib import Path

ALLOWED_WRITE_DIR = Path("/tmp/agent-sandbox")
ALLOWED_WRITE_DIR.mkdir(parents=True, exist_ok=True)

def safe_write_file(filename: str, content: str) -> str:
    """Write only to the sandbox directory; reject path traversal attempts."""
    target = (ALLOWED_WRITE_DIR / filename).resolve()
    if not str(target).startswith(str(ALLOWED_WRITE_DIR)):
        raise PermissionError(f"Path traversal blocked: {filename}")
    target.write_text(content)
    return f"Written: {target}"

def safe_run_python(code: str, timeout: int = 10) -> str:
    """Run Python code in a subprocess with a hard timeout and no network."""
    with tempfile.NamedTemporaryFile(suffix=".py", mode="w", delete=False) as f:
        f.write(code)
        script_path = f.name
    try:
        result = subprocess.run(
            ["python3", script_path],
            capture_output=True, text=True,
            timeout=timeout,
            env={**os.environ, "PYTHONPATH": ""},  # strip custom pythonpath
        )
        if result.returncode != 0:
            return f"ERROR:\n{result.stderr[:500]}"
        return result.stdout[:2000]
    except subprocess.TimeoutExpired:
        return "ERROR: execution timeout exceeded"
    finally:
        os.unlink(script_path)

# Code sub-agent uses safe tools only
def sandboxed_code_sub_agent(task: str, context: dict) -> SubAgentResult:
    try:
        resp = haiku.invoke([
            {"role": "system", "content": (
                "Write Python code that solves the task. "
                "Output only the code, no markdown fences."
            )},
            {"role": "user", "content": task},
        ])
        output = safe_run_python(resp.content)
        return SubAgentResult(success=True, output=output)
    except Exception as exc:
        return SubAgentResult(success=False, output="", error=str(exc))

import asyncio
from langchain_anthropic import ChatAnthropic

async def async_sub_agent(
    capability: str,
    task: str,
    llm: ChatAnthropic,
) -> SubAgentResult:
    try:
        resp = await llm.ainvoke([
            {"role": "system", "content": f"You are a {capability} specialist."},
            {"role": "user",   "content": task},
        ])
        return SubAgentResult(success=True, output=resp.content)
    except Exception as exc:
        return SubAgentResult(success=False, output="", error=str(exc))

async def parallel_sub_agents(task: str) -> list[SubAgentResult]:
    """Spawn code and search sub-agents in parallel."""
    code_task   = f"Write code to: {task}"
    search_task = f"Find information about: {task}"

    results = await asyncio.gather(
        async_sub_agent("code",   code_task,   haiku),
        async_sub_agent("search", search_task, haiku),
        return_exceptions=True,
    )
    return [
        r if isinstance(r, SubAgentResult)
        else SubAgentResult(success=False, output="", error=str(r))
        for r in results
    ]

# Usage
results = asyncio.run(parallel_sub_agents("fibonacci sequence"))
for r in results:
    if r.success:
        print(r.output[:200])
